func TestLoadAddsProjectScopeHeaderFromEnv(t *testing.T) {
	t.Setenv("SUPERMEMORY_ADMIN_PROJECT", "project_123")
	t.Setenv("SUPERMEMORY_ADMIN_CONFIG", filepath.Join(t.TempDir(), "config.toml"))

	cfg, err := Load("")
	if err != nil {
		t.Fatalf("Load: %v", err)
	}
	if got := cfg.Headers["x-sm-project"]; got != "project_123" {
		t.Fatalf("x-sm-project header = %q, want project_123", got)
	}
}

func TestLoadKeepsConfiguredHeadersWhenProjectEnvSet(t *testing.T) {
	dir := t.TempDir()
	cfgPath := filepath.Join(dir, "config.toml")
	if err := os.WriteFile(cfgPath, []byte("[headers]\nX-Trace = \"trace_abc\"\n"), 0o600); err != nil {
		t.Fatalf("write config: %v", err)
	}
	t.Setenv("SUPERMEMORY_ADMIN_CONFIG", cfgPath)
	t.Setenv("SUPERMEMORY_ADMIN_PROJECT", "project_123")

	cfg, err := Load("")
	if err != nil {
		t.Fatalf("Load: %v", err)
	}
	if got := cfg.Headers["X-Trace"]; got != "trace_abc" {
		t.Fatalf("X-Trace header = %q, want trace_abc", got)
	}
	if got := cfg.Headers["x-sm-project"]; got != "project_123" {
		t.Fatalf("x-sm-project header = %q, want project_123", got)
	}
}
